// break — exits the current loop entirely
for (let i = 0; i < 10; i++) {
  if (i === 5) break;   // stops at 5
  console.log(i);       // 0 1 2 3 4
}

// continue — skips to the next iteration
for (let i = 0; i < 10; i++) {
  if (i % 2 === 0) continue; // skip even numbers
  console.log(i);             // 1 3 5 7 9
}

